package main

import (
	"crypto/md5"
	"encoding/hex"
	"fmt"
	"io"
	"mime/multipart"
	"net/http"
	"os"
	"path/filepath"
	"strings"
	"time"
)

const (
	maxFileSize     = 10 << 20 // 10MB
	publicDir       = "./public/uploads"
	secureDir       = "./secure/uploads"
	allowedMimeTypes = "image/jpeg,image/png,image/gif,application/pdf,application/zip,application/x-rar-compressed,application/x-tar,application/x-7z-compressed,text/plain,application/msword,application/vnd.openxmlformats-officedocument.wordprocessingml.document,application/vnd.ms-excel,application/vnd.openxmlformats-officedocument.spreadsheetml.sheet"
)

var allowedMimeTypesMap = map[string]bool{
	"image/jpeg": true,
	"image/png":  true,
	"image/gif":  true,
	"application/pdf": true,
	"application/zip": true,
	"application/x-rar-compressed": true,
	"application/x-tar": true,
	"application/x-7z-compressed": true,
	"text/plain": true,
	"application/msword": true,
	"application/vnd.openxmlformats-officedocument.wordprocessingml.document": true,
	"application/vnd.ms-excel": true,
	"application/vnd.openxmlformats-officedocument.spreadsheetml.sheet": true,
}

func uploadHandler(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	// Parse multipart form with max memory of 10MB
	err := r.ParseMultipartForm(maxFileSize)
	if err != nil {
		http.Error(w, "Failed to parse form", http.StatusBadRequest)
		return
	}

	file, handler, err := r.FormFile("file")
	if err != nil {
		http.Error(w, "Failed to get file", http.StatusBadRequest)
		return
	}
	defer file.Close()

	// Validate file size
	if handler.Size > maxFileSize {
		http.Error(w, "File too large", http.StatusRequestEntityTooLarge)
		return
	}

	// Validate MIME type
	buffer := make([]byte, 512)
	n, err := file.Read(buffer)
	if err != nil {
		http.Error(w, "Failed to read file", http.StatusInternalServerError)
		return
	}
	file.Seek(0, 0)

	mimeType := http.DetectContentType(buffer[:n])
	if !allowedMimeTypesMap[mimeType] {
		http.Error(w, "Invalid file type", http.StatusUnsupportedMediaType)
		return
	}

	// Generate secure filename
	ext := filepath.Ext(handler.Filename)
	filename := generateSecureFilename(ext)

	// Determine storage path
	var storagePath string
	if strings.HasPrefix(mimeType, "image/") {
		storagePath = filepath.Join(publicDir, filename)
	} else {
		storagePath = filepath.Join(secureDir, filename)
	}

	// Ensure directories exist
	err = os.MkdirAll(filepath.Dir(storagePath), 0755)
	if err != nil {
		http.Error(w, "Failed to create storage directory", http.StatusInternalServerError)
		return
	}

	// Save file
	dst, err := os.Create(storagePath)
	if err != nil {
		http.Error(w, "Failed to create file", http.StatusInternalServerError)
		return
	}
	defer dst.Close()

	// Copy file content
	_, err = io.Copy(dst, file)
	if err != nil {
		http.Error(w, "Failed to save file", http.StatusInternalServerError)
		return
	}

	// Return file path
	var responsePath string
	if strings.HasPrefix(mimeType, "image/") {
		responsePath = filepath.Join("/uploads", filename)
	} else {
		responsePath = filepath.Join("/secure", filename)
	}

	w.Header().Set("Content-Type", "application/json")
	fmt.Fprintf(w, `{"path": "%s"}`, responsePath)
}

func generateSecureFilename(ext string) string {
	timestamp := time.Now().UnixNano()
	hash := md5.Sum([]byte(fmt.Sprintf("%d%s", timestamp, ext)))
	return hex.EncodeToString(hash[:]) + ext
}

func main() {
	// Create necessary directories
	os.MkdirAll(publicDir, 0755)
	os.MkdirAll(secureDir, 0755)

	http.HandleFunc("/upload", uploadHandler)
	http.ListenAndServe(":8080", nil)
}